using BgCommon.Localization;namespace BgControls.Windows.Controls.DragDrop;internal class WPFSimulatedDragDropProvider : SimulatedDragDropProvider{    private List<UIElement> dropTargetsHelper = new List<UIElement>(40);    private WeakReference adorner = new WeakReference(null);    private WeakReference hostRootVisual;    internal bool IsCancelling { get; set; }    internal override bool IsMouseDown    {        get        {            if (Mouse.LeftButton != MouseButtonState.Pressed)            {                return this.IsMouseDown;            }            return true;        }        set        {            base.IsMouseDown = value;        }    }    private DragDropAdorner? Adorner    {        get { return adorner.Target as DragDropAdorner; }        set { adorner = new WeakReference(value); }    }    private FrameworkElement? HostRootVisual    {        get        {            if (hostRootVisual != null && hostRootVisual.IsAlive)            {                return hostRootVisual.Target as FrameworkElement;            }            return null;        }        set        {            hostRootVisual = new WeakReference(value);        }    }    public override void SetAllowDrag(DependencyObject obj, bool value)    {        base.SetAllowDrag(obj, value);        if (!RadControl.IsInDesignMode)        {            var uIElement = obj as UIElement;            if (uIElement != null)            {                if (value)                {                    uIElement.RemoveHandler(UIElement.PreviewMouseLeftButtonDownEvent, new MouseButtonEventHandler(OnTrackedPartMouseLeftButtonDown));                    uIElement.AddHandler(UIElement.PreviewMouseLeftButtonDownEvent, new MouseButtonEventHandler(OnTrackedPartMouseLeftButtonDown), handledEventsToo: true);                }                else                {                    uIElement.RemoveHandler(UIElement.PreviewMouseLeftButtonDownEvent, new MouseButtonEventHandler(OnTrackedPartMouseLeftButtonDown));                }            }        }    }    public override void Dispose()    {        ClosePopup();        if (this.CoverRectangle != null)        {            this.CoverRectangle.Children.Clear();        }    }    internal override void FindRootVisual()    {        base.FindRootVisual();        if (this.RootVisual != null)        {            FrameworkElement? frameworkElement = null;            if (this.Options.Source == null)            {                if (Application.Current != null && Application.Current.CheckAccess() && Application.Current.MainWindow != null)                {                    frameworkElement = Application.Current.MainWindow.Content as FrameworkElement;                }            }            else            {                frameworkElement = Window.GetWindow(base.Options.Source);            }            if (frameworkElement == null)            {                frameworkElement = HostRootVisual;            }            if (frameworkElement == this.RootVisual)            {                return;            }            this.RootVisual = null;        }        if (this.RootVisual != null)        {            return;        }        if (this.Options.Source == null)        {            if (Application.Current != null && Application.Current.CheckAccess() && Application.Current.MainWindow != null)            {                this.RootVisual = Application.Current.MainWindow.Content as FrameworkElement;            }        }        else        {            this.RootVisual = Window.GetWindow(this.Options.Source);        }        if (this.RootVisual == null)        {            this.RootVisual = HostRootVisual;        }    }    internal override bool CanStartDrag()    {        return !this.IsDragging && !IsCancelling;    }    internal override void TryStartDrag(IMouseEventArgs e)    {        base.TryStartDrag(e);        if (this.Options.Source == null ||            (this.Options.Source != null && ArePointsNear(e.GetPosition(this.Options.Source))) || this.IsDragging)        {            return;        }        var queryResult = RaiseDragQuery().QueryResult;        if (queryResult.HasValue && queryResult.Value)        {            if (Mouse.Captured != null)            {                Mouse.Captured.ReleaseMouseCapture();            }            else if (!this.IsDragging)            {                StartDragging();                PositionPopup();            }        }    }    internal override void StartDraggingInternal()    {        if (this.Options.DragCue != null)        {            if (this.RootVisual == null)            {                FindRootVisual();            }            ContentControl contentControl = new ContentControl();            contentControl.Content = this.Options.DragCue;            ContentControl contentControl2 = contentControl;            contentControl2.HorizontalAlignment = HorizontalAlignment.Left;            contentControl2.VerticalAlignment = VerticalAlignment.Top;            Grid? grid = null;            if (this.CoverRectangle == null)            {                grid = new Grid();                this.CoverRectangle = grid;                this.CoverRectangle.RenderTransform = new TranslateTransform();                this.CoverRectangle.Background = new SolidColorBrush(Colors.Transparent);                this.CoverRectangle.MouseMove += OnCoverRectangleMouseMove;                this.CoverRectangle.MouseLeftButtonUp += OnCoverRectangleMouseLeftButtonUp;            }            this.CoverRectangle.Children.Add(contentControl2);            OpenPopup();        }    }    internal override void Reset()    {        base.Reset();        if (Application.Current == null &&            this.Options != null &&            this.Options.Source != null &&            RadControl.IsInElementHost(this.Options.Source))        {            this.RootVisual = null;            this.HostRootVisual = null;            this.IsInitialized = false;        }        ClosePopup();        if (this.CoverRectangle != null)        {            this.CoverRectangle.Children.Clear();            this.CoverRectangle = null;        }        Adorner = null;    }    internal override void SetCursor()    {        Mouse.OverrideCursor = this.Options.CurrentCursor;    }    internal override void ResetCursor()    {        Mouse.OverrideCursor = null;    }    internal override FrameworkElement? GetDragCueHost()    {        if (this.CoverRectangle == null || this.CoverRectangle.Children.Count == 0)        {            return null;        }        return this.CoverRectangle.Children[0] as FrameworkElement;    }    internal override void OnTrackedPartMouseLeftButtonDownInternal(object sender, IMouseButtonEventArgs e)    {        if (this.IsDragging)        {            CancelDragging();        }        var frameworkElement = sender as FrameworkElement;        this.Options = GetDefaultOptions();        this.Options.Source = frameworkElement;        UpdateMousePointInformation(e, frameworkElement);        if (frameworkElement != null)        {            InitHostRoot(frameworkElement);        }        FindRootVisual();    }    protected override void AddRootVisualHandlers(FrameworkElement root)    {        base.AddRootVisualHandlers(root);        root?.AddHandler(UIElement.MouseMoveEvent, new MouseEventHandler(OnCoverRectangleMouseMove), handledEventsToo: true);    }    protected override List<UIElement> GetElementsUnderMouse()    {        List<UIElement> list = new List<UIElement>(100);        if (this.Options.ParticipatingVisualRoots != null)        {            foreach (UIElement participatingVisualRoot in this.Options.ParticipatingVisualRoots)            {                _ = participatingVisualRoot;                VisualTreeHelper.HitTest(                    this.RootVisual,                    null,                    el =>                    {                        AddHitTestToDropZones(el);                        return HitTestResultBehavior.Continue;                    },                    new PointHitTestParameters(this.Options.CurrentDragPoint));                list.AddRange(dropTargetsHelper);                dropTargetsHelper.Clear();            }        }        VisualTreeHelper.HitTest(            this.RootVisual,            null,            el =>            {                AddHitTestToDropZones(el);                return HitTestResultBehavior.Continue;            },            new PointHitTestParameters(this.Options.CurrentDragPoint));        foreach (UIElement item in dropTargetsHelper)        {            if (item != null)            {                if (!list.Contains(item))                {                    list.Add(item);                }                foreach (UIElement ancestor in item.GetAncestors<UIElement>())                {                    if (!list.Contains(ancestor) && ancestor != null)                    {                        list.Add(ancestor);                    }                }            }        }        dropTargetsHelper.Clear();        return list;    }    protected override void RemoveRootVisualHandlers(FrameworkElement root)    {        base.RemoveRootVisualHandlers(root);        root?.RemoveHandler(UIElement.MouseMoveEvent, new MouseEventHandler(OnCoverRectangleMouseMove));    }    protected override void CancelDragging()    {        this.IsCancelling = true;        try        {            this.IsDragging = false;            this.NotifyPreviousApprovedDestination();            this.ClosePopup();            this.Options.Status = DragStatus.DragCancel;            this.RaiseDragInfo();            this.Options.Status = DragStatus.None;            this.Reset();        }        finally        {            this.IsCancelling = false;        }    }    private void OnTrackedPartMouseLeftButtonDown(object sender, MouseButtonEventArgs e)    {        if (e.ClickCount == 1)        {            OnTrackedPartMouseLeftButtonDownInternal(sender, new TestableMouseButtonEventArgs(e));        }    }    private void OnCoverRectangleMouseMove(object sender, MouseEventArgs e)    {        OnCoverRectangleMouseMoveInternal(new TestableMouseEventArgs(e));    }    private void OnCoverRectangleMouseLeftButtonUp(object sender, EventArgs e)    {        OnCoverRectangleMouseLeftButtonUpInternal();    }    private void OpenPopup()    {        var element = this.RootVisual;        FrameworkElement? frameworkElement = (from c in element?.ChildrenOfType<Panel>()?.Take(15)                                              where AdornerLayer.GetAdornerLayer(c) != null                                              select c).FirstOrDefault();        if (frameworkElement != null)        {            AdornerLayer adornerLayer = AdornerLayer.GetAdornerLayer(frameworkElement);            if (adornerLayer == null)            {                frameworkElement = frameworkElement.GetFirstDescendantOfType<ContentPresenter>();                if (frameworkElement != null)                {                    adornerLayer = AdornerLayer.GetAdornerLayer(frameworkElement);                }                if (adornerLayer == null)                {                    throw new InvalidOperationException(LocalizationProviderFactory.GetString("DragDropMissingAdornerLayer"));                }            }            if (Adorner != null)            {                AdornerLayer.GetAdornerLayer(Adorner.AdornedElement)?.Remove(Adorner);                Adorner.Dispose();                Adorner = null;            }            if (Adorner == null)            {                Adorner = new DragDropAdorner(frameworkElement, this.CoverRectangle);                adornerLayer.Add(Adorner);            }        }        if (this.CoverRectangle != null)        {            this.CoverRectangle.Visibility = Visibility.Visible;        }    }    private void ClosePopup()    {        if (this.CoverRectangle != null)        {            this.CoverRectangle.Visibility = Visibility.Collapsed;        }    }    private void AddHitTestToDropZones(HitTestResult hitTest)    {        if (hitTest.VisualHit is FrameworkElement { IsHitTestVisible: not false, IsVisible: not false } frameworkElement)        {            dropTargetsHelper.Add(frameworkElement);        }    }    private void InitHostRoot(DependencyObject target)    {        if (target is Visual visual && Application.Current == null && RadControl.IsInElementHost(target))        {            var presentationSource = PresentationSource.FromVisual(visual);            HostRootVisual = presentationSource.RootVisual as FrameworkElement;        }    }}